module RefModule (
    input wire [3:0] a,
    input wire [3:0] b,
    input wire cin,
    output wire [3:0] sum,
    output wire cout
);

    wire [3:0] obf_carry;

    assign {obf_carry[0], sum[0]} = a[0] + b[0] + cin;
    assign {obf_carry[1], sum[1]} = a[1] + b[1] + obf_carry[0];
    assign {obf_carry[2], sum[2]} = a[2] + b[2] + obf_carry[1];
    assign {obf_carry[3], sum[3]} = a[3] + b[3] + obf_carry[2];
    assign cout = obf_carry[3];

endmodule
